import{c as p,Q as o,j as t,m as a}from"./chunks/framework.D9IbVcwA.js";const x=JSON.parse('{"title":"003-boot-long-mode-2 · Long Mode","description":"","frontmatter":{"title":"003-boot-long-mode-2 · Long Mode"},"headers":[],"relativePath":"hands-on/003-boot-long-mode-2.md","filePath":"hands-on/003-boot-long-mode-2.md","lastUpdated":1779686691000}'),n={name:"hands-on/003-boot-long-mode-2.md"};function l(r,e,s,i,P,d){return o(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="_003-2-页表构建-setup-page-tables-设计与实现" tabindex="-1">003-2 页表构建：setup_page_tables() 设计与实现 <a class="header-anchor" href="#_003-2-页表构建-setup-page-tables-设计与实现" aria-label="Permalink to &quot;003-2 页表构建：setup_page_tables() 设计与实现&quot;">​</a></h1><blockquote><p>标签：x86_64, 长模式, 四级页表, 2MB 大页, 恒等映射, 高半内核 前置：<a href="./003-boot-long-mode-1">003-1 Long Mode 概念与页表设计</a></p></blockquote><h2 id="本篇目标" tabindex="-1">本篇目标 <a class="header-anchor" href="#本篇目标" aria-label="Permalink to &quot;本篇目标&quot;">​</a></h2><p>上一篇我们把 Long Mode 的概念和页表设计理清楚了，现在该动手了。</p><p>本篇的核心任务是实现 <code>setup_page_tables</code> 函数——</p><p>在固定物理地址 0x1000-0x3FFF 上搭建一套三级页表结构（PML4 → PDPT → PD），</p><p>用 2MB 大页恒等映射前 8MB 物理内存，</p><p>同时建立 Higher-Half Kernel 映射</p><p>（PML4[511]→PDPT[510]→PD[0]，将虚拟地址 0xFFFFFFFF80000000 映射到物理地址 0x00000000）。</p><p>这个函数封装在 <code>boot/common/long_mode.S</code> 中，是整个 Long Mode 切换的前半段。</p><h2 id="step-1-创建-long-mode-模块文件" tabindex="-1">Step 1: 创建 Long Mode 模块文件 <a class="header-anchor" href="#step-1-创建-long-mode-模块文件" aria-label="Permalink to &quot;Step 1: 创建 Long Mode 模块文件&quot;">​</a></h2><p><strong>目标</strong>：创建 <code>boot/common/long_mode.S</code> 文件，作为 Long Mode 切换的独立模块。</p><p><strong>设计思路</strong>：</p><p>把 Long Mode 相关的函数（页表初始化、模式切换）从 stage2.S 中独立出来，</p><p>放到 common 目录下作为单独的汇编文件。</p><p>这样做的好处是 stage2.S 不会继续膨胀，</p><p>而且 Long Mode 的初始化逻辑可以被其他启动路径复用。</p><p>这个文件需要在头部用 <code>.code32</code> 标记，因为它是在保护模式下被调用的。</p><p><strong>实现约束</strong>：</p><p>文件需要定义两组常量。</p><p>第一组是页表的物理地址布局——</p><p>PML4 放在 0x1000、PDPT 放在 0x2000、PD 放在 0x3000，</p><p>这是固定地址，因为 Bootloader 阶段没有动态内存分配。</p><p>第二组是控制位掩码——</p><ul><li>PAGE_PRESENT（0x01）：页表条目的存在位</li><li>PAGE_WRITABLE（0x02）：读写位</li><li>PAGE_LARGE（0x80）：大页标志位（2MB 页）</li><li>MSR_EFER（0xC0000080）：EFER 寄存器的 MSR 地址</li><li>EFER_LME（0x100）：Long Mode Enable 位的值</li><li>CR4_PAE（0x20）：PAE 位的掩码</li><li>CR0_PG（0x80000000）：分页使能位</li><li>CR0_PE（0x01）：保护模式使能位</li></ul><p>另外还需要定义 DEBUGCON_PORT（0xE9）和 CHAR_LONG_MODE（0x4C，即字符 &#39;L&#39;）用于调试输出。</p><p><strong>踩坑预警</strong>：</p><p>EFER_LME 的值是 0x100（bit 8），绝对不能写成 0x1000。</p><p>0x1000 对应的是 bit 12，即 AMD 的 SVME（Secure Virtual Machine Enable）位。</p><p>如果写错了，CPU 不会报错——<code>wrmsr</code> 会很乖地设置 SVME 位而不是 LME 位——</p><p>但当你随后开启分页时，CPU 发现 LME 没设却开了分页，直接三重故障。</p><p>这个坑是我们在开发时实打实踩过的，</p><p>GDB 里看到 EFER=0x1000 只有 SVME 没有 LME，定位了半天才发现是常量定义写错了一位。</p><p>调试这种问题时，在 GDB 里用 <code>info registers</code> 查看 CR0、CR4 和 EFER 的值是最直接的排查手段。</p><p><strong>验证</strong>：此时只需要确认文件被创建、常量定义正确即可，构建验证在后续步骤完成。</p><h2 id="step-2-实现页表清零逻辑" tabindex="-1">Step 2: 实现页表清零逻辑 <a class="header-anchor" href="#step-2-实现页表清零逻辑" aria-label="Permalink to &quot;Step 2: 实现页表清零逻辑&quot;">​</a></h2><p><strong>目标</strong>：清零 PML4（0x1000）、PDPT（0x2000）、PD（0x3000）三张页表。</p><p><strong>设计思路</strong>：</p><p>页表初始化的第一步是清零——</p><p>确保所有条目初始值为 0，这样未使用的条目的 Present 位就是 0，CPU 不会把残留的垃圾数据当成有效条目。</p><p>三张表各占 4KB（即 1024 个 32 位双字），</p><p>用 <code>rep stosl</code> 指令批量写入零值来清零。</p><p><code>rep stosl</code> 的意思是：把 EAX 的值（这里是 0）重复写入 ES:EDI 指向的内存地址 ECX 次，</p><p>每次写入后 EDI 自动递增 4。</p><p>函数开头需要先用 <code>cld</code> 指令清除方向标志位，</p><p>确保 <code>stosl</code> 是递增写入而非递减——</p><p>虽然正常情况下 DF 应该是 0，但在函数入口再确认一次是防御性编程。</p><p><strong>实现约束</strong>：</p><p>函数需要依次清零三个地址。</p><p>每次清零操作都是设置 EDI 为目标地址、EAX 为 0、ECX 为 1024，然后执行 <code>rep stosl</code>。</p><p>页表条目是 64 位的，但我们用 32 位的 <code>stosl</code> 写 0 来清零——</p><p>连续写两次 32 位的 0 等价于写一次 64 位的 0，所以没问题。</p><p>函数会修改 EAX、ECX、EDI 寄存器。</p><p><strong>验证</strong>：</p><p>在 GDB 中可以在 <code>setup_page_tables</code> 的清零完成后设断点，</p><p>用 <code>x/8gx 0x1000</code>、<code>x/8gx 0x2000</code>、<code>x/8gx 0x3000</code> 查看三张表的内容，应该全部为 0。</p><h2 id="step-3-建立层级链接" tabindex="-1">Step 3: 建立层级链接 <a class="header-anchor" href="#step-3-建立层级链接" aria-label="Permalink to &quot;Step 3: 建立层级链接&quot;">​</a></h2><p><strong>目标</strong>：设置 PML4[0] → PDPT 和 PDPT[0] → PD 的链接关系。</p><p><strong>设计思路</strong>：</p><p>清零完成后，需要建立三级页表之间的链接。</p><p>PML4 的第 0 个条目写入 PDPT 的物理地址（0x2000）加上 Present+Writable 标志（0x03），</p><p>PDPT 的第 0 个条目写入 PD 的物理地址（0x3000）加上同样的标志。</p><p>这样 CPU 在做地址翻译时，</p><p>从 CR3 找到 PML4，从 PML4[0] 找到 PDPT，从 PDPT[0] 找到 PD。</p><p>为什么只设置第 0 个条目？</p><p>因为 PML4[0] 覆盖的虚拟地址范围是 0x0000000000000000 到 0x0000007FFFFFFFFF</p><p>（即第一个 512GB 区域），PDPT[0] 覆盖的是这个 512GB 区域中的第一个 1GB，对 Bootloader 阶段完全足够。</p><p><strong>实现约束</strong>：</p><p>用 <code>movl</code> 把下一级页表物理地址加上 0x03 标志写入当前级页表的第 0 个条目。</p><p>注意这里用 <code>movl</code> 做的是 32 位写入，只写了条目的低 32 位，</p><p>高 32 位保持为 0（之前清零了）——</p><p>对于 8MB 以下的物理地址这是正确的，</p><p>Intel SDM Vol.3A §4.5 要求页表条目中未实现的保留位必须为 0。</p><p><strong>验证</strong>：</p><p>GDB 中检查 PML4[0] = 0x2003（PDPT 地址 + 标志），PDPT[0] = 0x3003（PD 地址 + 标志）。</p><h2 id="step-4-填充-pd-大页条目——恒等映射" tabindex="-1">Step 4: 填充 PD 大页条目——恒等映射 <a class="header-anchor" href="#step-4-填充-pd-大页条目——恒等映射" aria-label="Permalink to &quot;Step 4: 填充 PD 大页条目——恒等映射&quot;">​</a></h2><p><strong>目标</strong>：填充 PD 的前 4 个条目，每个条目映射一个 2MB 大页，实现前 8MB 物理内存的恒等映射。</p><p><strong>设计思路</strong>：</p><p>PD 条目的 bit 7（PS，Page Size）设为 1 表示这是一个 2MB 大页，</p><p>bit 0（Present）和 bit 1（Writable）也设为 1。</p><p>第 i 个条目的物理基地址等于 i 左移 21 位（即 i × 2MB）。具体来说：</p><ul><li>PD[0] 映射 0x00000000-0x001FFFFF（0-2MB）</li><li>PD[1] 映射 0x00200000-0x003FFFFF（2-4MB）</li><li>PD[2] 映射 0x00400000-0x005FFFFF（4-6MB）</li><li>PD[3] 映射 0x00600000-0x007FFFFF（6-8MB）</li></ul><p>总共 8MB 的恒等映射，对 Bootloader 阶段绰绰有余。</p><p><strong>实现约束</strong>：</p><p>用一个循环实现——</p><p>EDI 指向 PD 起始地址，ECX=4 控制循环次数，EAX 从 0 开始作为页索引。</p><p>每次迭代把 EAX 左移 21 位得到物理基地址，OR 上 0x83 标志，写入 EDI 指向的位置，</p><p>然后 EDI 前进 8 字节（条目大小），EAX 自增。</p><p><strong>验证</strong>：</p><p>GDB 中用 <code>x/8gx 0x3000</code> 查看 PD，</p><p>PD[0..3] 分别是 0x83、0x200083、0x400083、0x600083。</p><h2 id="step-5-建立-higher-half-kernel-映射" tabindex="-1">Step 5: 建立 Higher-Half Kernel 映射 <a class="header-anchor" href="#step-5-建立-higher-half-kernel-映射" aria-label="Permalink to &quot;Step 5: 建立 Higher-Half Kernel 映射&quot;">​</a></h2><p><strong>目标</strong>：设置 PML4[511] → PDPT 和 PDPT[510] → PD 的链接，实现 Higher-Half Kernel 映射。</p><p><strong>设计思路</strong>：</p><p>恒等映射只能让内核跑在低地址。</p><p>为了让内核运行在高半地址空间（0xFFFFFFFF80000000 以上），我们需要额外的映射。</p><p>虚拟地址 0xFFFFFFFF80000000 的拆解是：</p><ul><li>PML4 索引 = bit 47:39 = 0x1FF = 511</li><li>PDPT 索引 = bit 38:30 = 0x1FE = 510（注意是 510 而不是 511，因为 bit 30 为 0）</li><li>PD 索引 = bit 29:21 = 0x000 = 0</li></ul><p>所以我们需要设置 PML4[511] 指向 PDPT，PDPT[510] 指向 PD。</p><p>PD[0] 就是那条映射 0-2MB 的大页条目，已经在 Step 4 中设好了——</p><p>所以 Higher-Half 映射只需要添加两个链接条目即可。</p><p><strong>实现约束</strong>：</p><p>PML4[511] 写入 PDPT 物理地址 + 0x03 标志（和 PML4[0] 一样），</p><p>PDPT[510] 写入 PD 物理地址 + 0x03 标志（和 PDPT[0] 一样）。</p><p>但是！这里有一个关键区别：</p><p>因为 x86-64 页表条目是 64 位的，而且 PML4[511] 和 PDPT[510] 是&quot;非常用&quot;条目，</p><p>虽然物理地址在 4GB 以下高 32 位应该为 0，</p><p>但为了安全起见，必须显式地把高 32 位也写为 0。</p><p>具体来说，先写低 32 位（物理地址 + 标志），再写高 32 位为 0。</p><p>PML4[511] 的偏移是 PML4_PHYS_ADDR + (511 * 8)，</p><p>PDPT[510] 的偏移是 PDPT_PHYS_ADDR + (510 * 8)。</p><p><strong>踩坑预警</strong>：</p><p>PDPT 索引是 510 不是 511。</p><p>如果你把 PDPT[511] 设成指向 PD，</p><p>那对应的虚拟地址是 0xFFFFFFFFC0000000 而不是 0xFFFFFFFF80000000——差了整整 1GB。</p><p>这个 off-by-one 错误在调试时非常难发现，</p><p>因为 CPU 不会报错，只是映射到了错误的地址。</p><p>我们是通过计算虚拟地址的二进制拆分才确认正确的索引是 510。</p><p><strong>验证</strong>：</p><p>GDB 中检查 PML4[511] = 0x2003（PDPT 地址 + 标志），PDPT[510] = 0x3003（PD 地址 + 标志）。</p><h2 id="构建验证" tabindex="-1">构建验证 <a class="header-anchor" href="#构建验证" aria-label="Permalink to &quot;构建验证&quot;">​</a></h2><p>完成以上步骤后，<code>setup_page_tables</code> 函数在 <code>ret</code> 返回时，</p><p>0x1000-0x3FFF 处的页表结构应该完整建立。</p><p>在 GDB 中可以用以下命令验证完整的页表内容：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) x/8gx 0x1000    # PML4: [0]=0x2003, [511]=0x2003</span></span>
<span class="line"><span>(gdb) x/8gx 0x2000    # PDPT: [0]=0x3003, [510]=0x3003</span></span>
<span class="line"><span>(gdb) x/8gx 0x3000    # PD: [0]=0x83, [1]=0x200083, [2]=0x400083, [3]=0x600083</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>下一篇我们将实现 <code>enter_long_mode</code> 函数，利用这套页表把 CPU 真正带入 64 位 Long Mode。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM Vol.3A §4.1 — Paging Overview：Long Mode 下分页的强制性</li><li>Intel SDM Vol.3A §4.5 — 4-Level Paging：PML4/PDPT/PD/PT 层级结构</li><li>Intel SDM Vol.3A §4.5.1 — Page Size Extensions：2MB 和 1GB 大页</li><li>Intel SDM Vol.3A §10.8.5 — Initializing IA-32e Mode：初始化步骤</li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Setting_Up_Long_Mode" target="_blank" rel="noreferrer">Setting Up Long Mode</a></li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Paging" target="_blank" rel="noreferrer">Paging</a></li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Higher_Half_Kernel" target="_blank" rel="noreferrer">Higher Half Kernel</a></li></ul>`,128)])])}const c=p(n,[["render",l]]);export{x as __pageData,c as default};
